What does this program print?

```cpp
#include <iostream>

struct Box
{
    int length;
    int width;
    int height;
};

int main()
{
    Box b{ 4, 3, 2 };
    std::cout << b.length << ' ' << b.width << ' ' << b.height << '\n';
    std::cout << b.length * b.width * b.height << '\n';
    return 0;
}
```

